INSERT INTO assistant_task VALUES(4,'VN-ED331D','2026-04-16 10:27:57.409084','Pending','verify_document','{"amount": null, "currency": null, "location": "Nanyuki", "document_type": "title deed", "urgency": "medium"}',75,'["Submit the title deed for verification", "Conduct a search at the relevant authorities", "Confirm the authenticity of the document"]',replace('Hello, we''re here to help you verify your title deed 📝. Please submit the document and we''ll conduct a search to confirm its authenticity. \nThis will ensure your 5-acre plot in Nanyuki is secure.','\n',char(10)),replace('Subject: Title Deed Verification for 5-Acre Plot in Nanyuki\nDear Sir/Madam,\nWe are writing to inform you that we will be verifying the title deed for your 5-acre plot in Nanyuki. Please find attached the required documents for submission.','\n',char(10)),'Verify title deed for 5ac Nanyuki plot','Legal',NULL);
