INSERT INTO assistant_task VALUES(7,'VN-390F59','2026-04-16 10:31:26.743506','Pending','verify_document','{"amount": null, "currency": null, "location": "Karen", "document_type": "title deed", "urgency": "high"}',95,'["Submit the title deed for verification", "Check the Ministry of Lands records", "Confirm the ownership and acreage"]','Hello, we''re verifying your 2-acre plot in Karen. We''ll check the title deed against the Ministry of Lands records and get back to you ASAP 📝👍',replace('Subject: Urgent: Title Deed Verification for Karen Plot\nDear Sir/Madam,\nWe are writing to verify the title deed for your 2-acre plot in Karen against the Ministry of Lands records.\nPlease find the details below:\nLocation: Karen\nDocument Type: Title Deed\nWe will expedite this process and notify you promptly.','\n',char(10)),'Verifying title deed for Karen plot. Will update soon.','Legal',NULL);
