INSERT INTO assistant_task VALUES(14,'VN-34EC78','2026-04-16 11:37:42.912778','Pending','hire_service','{"amount": null, "currency": null, "location": "Westlands", "document_type": null, "urgency": "medium"}',10,'["Identify and shortlist professional cleaners in Westlands", "Contact and schedule the cleaner for this Saturday", "Confirm the cleaning services and rates"]',replace('Hi, I need a professional cleaner for my house in Westlands this Saturday 🏠💪. Can you help me with that? 🤔\nPlease let me know the available time slots and rates.','\n',char(10)),replace('Subject: Hiring a Professional Cleaner for Saturday\nDear Team,\nI am in need of a professional cleaner for my house in Westlands this Saturday. Could you please assist me in finding a reliable cleaner and provide me with their rates and available time slots?\nThank you for your help.','\n',char(10)),'Need cleaner in Westlands Sat','Operations',NULL);
INSERT INTO assistant_task VALUES(15,'VN-A83B09','2026-04-16 11:40:57.439982','Pending','verify_document','{"amount": null, "currency": null, "location": "Syokimau", "document_type": "title deed", "urgency": "high"}',95,'["Gather all necessary documents", "Submit documents for verification", "Wait for verification results"]',replace('Hello, we''re here to help you verify that title deed in Syokimau 🏠👍. Don''t rush into anything, let''s make sure it''s legit first. \nWe''ll guide you through the process.','\n',char(10)),replace('Subject: Urgent: Title Deed Verification for Syokimau Plot\nDear Sir/Madam, \nWe are writing to assist you with the verification of a title deed for a plot in Syokimau. Please find the necessary steps below: \n1. Gather all necessary documents. \n2. Submit documents for verification. \n3. Wait for verification results. \nPlease do not hesitate to contact us if you require any further assistance.','\n',char(10)),'Verify title deed ASAP','Legal',NULL);
